 43	
 44	// Define the action types for the reducer
 45	type RHCSAction =
 46	  | { type: 'SET_FILE_DATA'; payload: string }
 47	  | { type: 'SET_ERROR_MESSAGE'; payload: string }
 48	  | { type: 'SET_IS_LOADING'; payload: boolean }
 49	  | { type: 'SET_FILE_NAME'; payload: string }
