 53	const initialState: RHCSState = {
 54	  fileData: '',
 55	  errorMessage: '',
 56	  isLoading: false,
 57	  fileName: '',
 58	};
 59	
 60	// Reducer function
 61	const reducer = (state: RHCSState, action: RHCSAction): RHCSState => {
 62	  switch (action.type) {
 63	    case 'SET_FILE_DATA':
 64	      return { ...state, fileData: action.payload };
 65	    case 'SET_ERROR_MESSAGE':
 66	      return { ...state, errorMessage: action.payload };
 67	    case 'SET_IS_LOADING':
 68	      return { ...state, isLoading: action.payload };
 69	    case 'SET_FILE_NAME':
 70	      return { ...state, fileName: action.payload };
 71	    case 'SET_FIELD':
 72	      return { ...state, [action.payload.key]: action.payload.value };
 73	    default:
 74	      return state;
 75	  }
 76	};
 77	
 78	// Custom dispatch function type that matches ConnectionDetails expectations
 79	type RHCSDispatch = (key: keyof RHCSState, value: any) => void;
 80	
 81	// Not to be exposed to other files to make our code name agnostic
 82	const OCS_EXTERNAL_CR_NAME = 'ocs-external-storagecluster';
 83	const OCS_MULTIPLE_CLUSTER_NS = 'openshift-storage-extended';
 84	
 85	const NOOBAA_DB_BACKUP_VOLUMESNAPSHOTCLASS =
 86	  getRBDVolumeSnapshotClassName(OCS_EXTERNAL_CR_NAME);
 87	
 88	// Initial state for advanced settings (backup + postgres)
 89	type AdvancedSettingsState = {
 90	  isDbBackup: boolean;
 91	  dbBackup: {
 92	    schedule: string;
 93	    volumeSnapshot: {
 94	      maxSnapshots: number;
 95	      volumeSnapshotClass: string;
 96	    };
 97	  };
 98	  useExternalPostgres: boolean;
 99	  externalPostgres: {
100	    username: string;
101	    password: string;
102	    serverName: string;
103	    port: string;
104	    databaseName: string;
105	    tls: {
106	      enabled: boolean;
107	      allowSelfSignedCerts: boolean;
108	      enableClientSideCerts: boolean;
109	      keys: {
110	        private: File;
111	        public: File;
112	      };
113	    };
114	  };
115	};
116	
117	const initialAdvancedSettingsState: AdvancedSettingsState = {
118	  isDbBackup: false,
119	  dbBackup: {
120	    schedule: '0 0 * * *',
121	    volumeSnapshot: {
122	      maxSnapshots: 5,
123	      volumeSnapshotClass: '',
124	    },
125	  },
126	  useExternalPostgres: false,
127	  externalPostgres: {
128	    username: '',
129	    password: '',
130	    serverName: '',
131	    port: null,
132	    databaseName: '',
133	    tls: {
134	      enabled: false,
135	      allowSelfSignedCerts: false,
136	      enableClientSideCerts: false,
137	      keys: {
138	        private: null,
139	        public: null,
140	      },
141	    },
142	  },
143	};
144	
145	// Reducer for advanced settings
146	const advancedSettingsReducer = (
147	  state: AdvancedSettingsState,
148	  action: CreateStorageSystemAction
149	): AdvancedSettingsState => {
150	  switch (action.type) {
151	    // Backup actions
152	    case 'advancedSettings/setDbBackup':
153	      return { ...state, isDbBackup: action.payload };
154	    case 'advancedSettings/dbBackup/schedule':
155	      return {
156	        ...state,
157	        dbBackup: { ...state.dbBackup, schedule: action.payload },
158	      };
159	    case 'advancedSettings/dbBackup/volumeSnapshot/maxSnapshots':
160	      return {
161	        ...state,
162	        dbBackup: {
163	          ...state.dbBackup,
164	          volumeSnapshot: {
165	            ...state.dbBackup.volumeSnapshot,
166	            maxSnapshots: action.payload,
167	          },
168	        },
169	      };
170	    case 'advancedSettings/dbBackup/volumeSnapshot/volumeSnapshotClass':
171	      return {
172	        ...state,
173	        dbBackup: {
174	          ...state.dbBackup,
175	          volumeSnapshot: {
176	            ...state.dbBackup.volumeSnapshot,
177	            volumeSnapshotClass: action.payload,
178	          },
179	        },
180	      };
181	    // Postgres actions
182	    case 'advancedSettings/useExternalPostgres':
183	      return { ...state, useExternalPostgres: action.payload };
184	    case 'advancedSettings/externalPostgres/setUsername':
185	      return {
186	        ...state,
187	        externalPostgres: {
188	          ...state.externalPostgres,
189	          username: action.payload,
190	        },
191	      };
192	    case 'advancedSettings/externalPostgres/setPassword':
193	      return {
194	        ...state,
195	        externalPostgres: {
196	          ...state.externalPostgres,
197	          password: action.payload,
198	        },
199	      };
200	    case 'advancedSettings/externalPostgres/setServerName':
201	      return {
202	        ...state,
203	        externalPostgres: {
204	          ...state.externalPostgres,
205	          serverName: action.payload,
206	        },
207	      };
208	    case 'advancedSettings/externalPostgres/setPort':
209	      return {
210	        ...state,
211	        externalPostgres: { ...state.externalPostgres, port: action.payload },
212	      };
213	    case 'advancedSettings/externalPostgres/setDatabaseName':
214	      return {
215	        ...state,
216	        externalPostgres: {
217	          ...state.externalPostgres,
218	          databaseName: action.payload,
219	        },
220	      };
221	    case 'advancedSettings/externalPostgres/tls/enableTLS':
222	      return {
223	        ...state,
224	        externalPostgres: {
225	          ...state.externalPostgres,
226	          tls: {
227	            ...state.externalPostgres.tls,
228	            enabled: action.payload,
229	          },
230	        },
231	      };
232	    case 'advancedSettings/externalPostgres/tls/allowSelfSignedCerts':
233	      return {
234	        ...state,
235	        externalPostgres: {
236	          ...state.externalPostgres,
237	          tls: {
238	            ...state.externalPostgres.tls,
239	            allowSelfSignedCerts: action.payload,
240	          },
241	        },
242	      };
243	    case 'advancedSettings/externalPostgres/tls/enableClientSideCerts':
244	      return {
245	        ...state,
246	        externalPostgres: {
247	          ...state.externalPostgres,
248	          tls: {
249	            ...state.externalPostgres.tls,
250	            enableClientSideCerts: action.payload,
251	          },
252	        },
253	      };
254	    case 'advancedSettings/externalPostgres/tls/keys/setPrivateKey':
255	      return {
256	        ...state,
257	        externalPostgres: {
258	          ...state.externalPostgres,
259	          tls: {
260	            ...state.externalPostgres.tls,
261	            keys: {
262	              ...state.externalPostgres.tls.keys,
263	              private: action.payload,
264	            },
265	          },
266	        },
267	      };
268	    case 'advancedSettings/externalPostgres/tls/keys/setPublicKey':
269	      return {
270	        ...state,
271	        externalPostgres: {
272	          ...state.externalPostgres,
273	          tls: {
274	            ...state.externalPostgres.tls,
275	            keys: {
276	              ...state.externalPostgres.tls.keys,
277	              public: action.payload,
278	            },
279	          },
280	        },
281	      };
282	    default:
283	      return state;
284	  }
285	};
286	const CreateCephCluster: React.FC = () => {
287	  const { t } = useCustomTranslation();
288	  const { odfNamespace, isNsSafe } = useODFNamespaceSelector();
289	  const [state, dispatch] = React.useReducer(reducer, initialState);
290	  const [encryption, setEncryption] = React.useState(false);
291	  const [isRBDStorageClassDefault, setRBDStorageClassDefault] =
292	    React.useState(false);
293	  const [isLoading, setIsLoading] = React.useState(false);
294	  const [error, setError] = React.useState(null);
295	
296	  // Single reducer for advanced settings (backup + postgres)
297	  const [advancedSettings, advancedDispatch] = React.useReducer(
298	    advancedSettingsReducer,
299	    initialAdvancedSettingsState
300	  );
301	
302	  const { isDbBackup, dbBackup, useExternalPostgres, externalPostgres } =
303	    advancedSettings;
304	
305	  const navigate = useNavigate();
306	  const redirectPath = '/odf/external-systems';
307	
308	  const { systemFlags, areFlagsLoaded, flagsLoadError } =
309	    useODFSystemFlagsSelector();
310	
311	  const [namespaces] = useK8sList(NamespaceModel);
312	
313	  const hasInternal =
314	    areFlagsLoaded && !flagsLoadError ? hasAnyInternalOCS(systemFlags) : false;
315	
316	  // Create a dispatch function that matches the expected interface
317	  const setFormState: RHCSDispatch = React.useCallback((key, value) => {
318	    dispatch({ type: 'SET_FIELD', payload: { key, value } });
319	  }, []);
320	  const onSubmit = async () => {
321	    setIsLoading(true);
322	
323	    try {
324	      const systemNamespace = !hasInternal
325	        ? odfNamespace
326	        : OCS_MULTIPLE_CLUSTER_NS;
327	      const nsAlreadyExists = !!(namespaces ?? []).find(
328	        (ns) => getName(ns) === systemNamespace
329	      );
330	      systemNamespace === odfNamespace || nsAlreadyExists
331	        ? await labelOCSNamespace(systemNamespace)
332	        : await createOCSNamespace(systemNamespace);
333	
334	      const payload = rhcsPayload({
335	        systemName: OCS_EXTERNAL_CR_NAME,
336	        state,
337	        namespace: systemNamespace,
338	        inTransitStatus: encryption,
339	        shouldSetCephRBDAsDefault: isRBDStorageClassDefault,
340	        isDbBackup,
341	        dbBackup: isDbBackup
342	          ? {
343	              ...dbBackup,
344	              volumeSnapshot: {
345	                ...dbBackup.volumeSnapshot,
346	                // Auto-set volumeSnapshotClass for external mode (isMCG=false)
347	                volumeSnapshotClass: NOOBAA_DB_BACKUP_VOLUMESNAPSHOTCLASS,
348	              },
349	            }
350	          : undefined,
351	      });
352	
353	      const promises = payload.map((p) =>
354	        k8sCreate({ model: p.model as K8sModel, data: p.payload })
355	      );
356	      await Promise.all(promises);
357	      navigate(redirectPath);
358	    } catch (e) {
359	      setError(e?.message ?? JSON.stringify(e));
360	    }
361	    setIsLoading(false);
362	  };
363	
364	  return (
365	    <>
366	      <PageHeading title={t('Connect Red Hat Ceph storage')}>
367	        <TextContent>
368	          <Text component={TextVariants.small}>
369	            {t(
370	              'Connect to a Red Hat Ceph cluster to unify and scale your block, file, and object storage with Data Foundation'
371	            )}
372	          </Text>
373	        </TextContent>
374	      </PageHeading>
375	      <div className="odf-m-pane__body">
376	        <TextContent>
377	          <Text component={TextVariants.h3}>
378	            {t('Configure connection network')}
379	          </Text>
380	        </TextContent>
381	        <div>
382	          <ConnectionDetails setFormState={setFormState} formState={state} />
383	        </div>
384	        <div className="pf-v6-u-mt-lg">
385	          <TextContent>
386	            <Text component={TextVariants.h3}>{t('Encryption')}</Text>
387	          </TextContent>
388	          <Checkbox
389	            className="pf-v6-u-mt-md"
390	            data-test="in-transit-encryption-checkbox"
391	            id="in-transit-encryption"
392	            isChecked={encryption}
393	            data-checked-state={encryption}
394	            label={t('In-transit encryption')}
395	            description={t(
396	              'Encrypts all Ceph traffic including data, using Ceph msgrv2'
397	            )}
398	            onChange={(_event, checked: boolean) => setEncryption(checked)}
399	          />
400	          <Alert
401	            variant={AlertVariant.info}
402	            isInline
403	            className="pf-v6-u-mt-sm"
404	            title={
405	              <>
406	                {t(
407	                  'Verify your RHCS cluster has the necessary in-transit encryption settings configured to enable in-transit encryption on your external cluster. Refer to the documentation for detailed configuration steps.'
408	                )}{' '}
409	                <a
410	                  href={inTransitEncryptionSettingsForRHCS(odfDocVersion)}
411	                  target="_blank"
412	                  rel="noopener noreferrer"
413	                >
414	                  {t('Documentation link')}
415	                </a>
416	              </>
417	            }
418	          />
419	        </div>
420	        <div className="pf-v6-u-mt-lg">
421	          <TextContent>
422	            <Text component={TextVariants.h3}>
423	              {t('Advanced configuration')}
424	            </Text>
425	          </TextContent>
426	          <SetCephRBDStorageClassDefault
427	            className="pf-v6-u-mt-md"
428	            dispatch={() =>
429	              setRBDStorageClassDefault((currState) => !currState)
430	            }
431	            isRBDStorageClassDefault={isRBDStorageClassDefault}
432	          />
433	          <Checkbox
434	            id="use-external-postgress"
435	            label={
436	              <>
437	                {t('Use external PostgreSQL')}
438	                <span className="pf-v6-u-ml-sm">
439	                  <TechPreviewBadge />
440	                </span>
441	              </>
442	            }
443	            description={t(
444	              'Allow Noobaa to connect to an external postgres server'
445	            )}
446	            isChecked={useExternalPostgres}
447	            onChange={(_event, checked: boolean) =>
448	              advancedDispatch({
449	                type: 'advancedSettings/useExternalPostgres',
450	                payload: checked,
451	              })
452	            }
453	            className="odf-backing-store__radio--margin-bottom"
454	            isDisabled={isDbBackup}
455	          />
456	          {useExternalPostgres && (
457	            <PostgresConnectionDetails
458	              dispatch={advancedDispatch}
459	              tlsFiles={[
460	                externalPostgres.tls.keys.private,
461	                externalPostgres.tls.keys.public,
462	              ]}
463	              tlsEnabled={externalPostgres.tls.enabled}
464	              allowSelfSignedCerts={externalPostgres.tls.allowSelfSignedCerts}
465	              username={externalPostgres.username}
466	              password={externalPostgres.password}
467	              serverName={externalPostgres.serverName}
468	              databaseName={externalPostgres.databaseName}
469	              port={externalPostgres.port}
470	              enableClientSideCerts={externalPostgres.tls.enableClientSideCerts}
471	            />
472	          )}
473	          <div className="pf-v6-u-my-md">
474	            <AutomaticBackup
475	              dispatch={advancedDispatch}
476	              isDbBackup={isDbBackup}
477	              isMCG={false}
478	              dbBackup={dbBackup}
479	              isExternalPostgresEnabled={useExternalPostgres}
480	            />
481	          </div>
482	        </div>
483	        {error && (
484	          <Alert variant={AlertVariant.danger} isInline title={error} />
485	        )}
486	        <Flex direction={{ default: 'row' }}>
487	          <FlexItem>
488	            <Button
489	              isLoading={isLoading}
490	              spinnerAriaLabel={t('Connecting')}
491	              onClick={onSubmit}
492	              variant={ButtonVariant.primary}
493	              isDisabled={isLoading || _.isEmpty(state.fileData) || !isNsSafe}
494	            >
495	              {isLoading ? t('Connecting') : t('Connect')}
496	            </Button>
497	          </FlexItem>
498	          <FlexItem>
499	            <Button onClick={() => navigate(-1)} variant={ButtonVariant.link}>
500	              {t('Cancel')}
501	            </Button>
502	          </FlexItem>
503	        </Flex>
504	      </div>
505	    </>
506	  );
507	};
508	
509	export default CreateCephCluster;

